example.code:
// In the service package (consumer side)
type UserStore interface {
    FindByID(ctx context.Context, id int) (*User, error)
    Save(ctx context.Context, user *User) error
}

// Manual mock for tests
type stubUserStore struct {
    user *User
    err  error
}

func (s *stubUserStore) FindByID(_ context.Context, _ int) (*User, error) {
    return s.user, s.err
}

func (s *stubUserStore) Save(_ context.Context, _ *User) error {
    return s.err
}

func TestGetUserHandler(t *testing.T) { store := &stubUserStore{user: &User{ID: 1, Name: "Alice"}} handler := NewUserHandler(store)
req := httptest.NewRequest(http.MethodGet, "/users/1", nil) rec := httptest.NewRecorder()
handler.ServeHTTP(rec, req)
require.Equal(t, http.StatusOK, rec.Code) var got User require.NoError(t, json.NewDecoder(rec.Body).Decode(&got)) assert.Equal(t, "Alice", got.Name) }

func TestAPIClient_GetUser(t *testing.T) {
    srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.Header().Set("Content-Type", "application/json")
        json.NewEncoder(w).Encode(User{ID: 1, Name: "Alice"})
    }))
    defer srv.Close()

    client := NewAPIClient(srv.URL)
    user, err := client.GetUser(context.Background(), 1)

    require.NoError(t, err)
    assert.Equal(t, "Alice", user.Name)
}
